-- Cria tabela `pais` em Cadastros como fonte única de país no Gravity.
--
-- 251 países seedeados de planilha consolidada (RFB nome PT + EN, códigos
-- Siscomex/MDIC/BACEN/SPED brasileiros, ISO 3166-1 alpha-2/alpha-3/numérico).
-- Planilha original tinha 252 entries — 1 duplicata removida ("Terras Austrais
-- e Antárcticas Francesas" com 'C', grafia desatualizada — mantida a versão
-- sem 'C', ortografia atual).
--
-- Brasil sempre primeiro (nome_pais_portugues='Brasil') — caso default da
-- maioria dos cadastros do produto. Demais ordenados alfabeticamente em
-- pt-BR.
--
-- Toda entidade que referencia país no Gravity (Empresa, Workspace,
-- Organizacao, AgenteCarga, Seguradora, etc.) deve apontar para id_pais.
-- Lei: skills/governanca/lei/cadastros-snapshot-policy/SKILL.md.
--
-- Constraints UNIQUE:
-- - nome_pais_portugues — único globalmente
-- - codigo_pais_iso_alpha2 — padrão ISO 3166-1 globalmente único
-- - codigo_pais_iso_alpha3 — padrão ISO 3166-1 globalmente único
-- - codigo_pais_portal_unico_siscomex — NÃO UNIQUE (planilha tem 4
--   códigos repetidos legitimamente: 359 cobre Antártida + Ilha de Man;
--   150 cobre Guernsey + Jersey; 360 cobre Ilha Heard + Terras Austrais
--   Francesas; 488 cobre Mauritânia + Mayotte)

CREATE TABLE "pais" (
  "id_pais"                            TEXT        NOT NULL,
  "nome_pais_portugues"                TEXT        NOT NULL,
  "nome_pais_ingles"                   TEXT        NOT NULL,
  "codigo_pais_portal_unico_siscomex"  TEXT,
  "codigo_pais_bacen_4"                TEXT,
  "codigo_pais_bacen_5"                TEXT,
  "codigo_pais_sped_nfe"               TEXT,
  "codigo_pais_sped_efd"               TEXT,
  "codigo_pais_iso_alpha2"             TEXT,
  "codigo_pais_iso_alpha3"             TEXT,
  "codigo_pais_iso_numerico"           TEXT,
  "ativo_pais"                         BOOLEAN     NOT NULL DEFAULT true,
  CONSTRAINT "pais_pkey" PRIMARY KEY ("id_pais")
);

CREATE UNIQUE INDEX "pais_nome_pais_portugues_key"     ON "pais"("nome_pais_portugues");
CREATE UNIQUE INDEX "pais_codigo_pais_iso_alpha2_key"  ON "pais"("codigo_pais_iso_alpha2");
CREATE UNIQUE INDEX "pais_codigo_pais_iso_alpha3_key"  ON "pais"("codigo_pais_iso_alpha3");
CREATE INDEX        "pais_nome_pais_portugues_idx"     ON "pais"("nome_pais_portugues");

-- Seed: 251 países (Brasil primeiro, demais alfabético pt-BR)

